spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var lineY = H / 2 - 10;
    var lineLen = 180;
    var startX = (W - lineLen) / 2;
    var endX = startX + lineLen;

    // Draw scale line
    ctx.beginPath();
    ctx.moveTo(startX, lineY);
    ctx.lineTo(endX, lineY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 4;
    ctx.stroke();

    // Five ticks: 0, 0.25, 0.5, 0.75, 1.0
    var tickCoords = [startX, startX + 45, startX + 90, startX + 135, endX];
    var tickDecs = ['0.0', '0.25', '0.50', '0.75', '1.0'];
    var tickFracs = ['0/1', '1/4', '1/2', '3/4', '1/1'];

    // Draw tick marks and labels
    ctx.font = '10px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    for (var i = 0; i < tickCoords.length; i++) {
      var tx = tickCoords[i];
      ctx.beginPath();
      ctx.moveTo(tx, lineY - 8);
      ctx.lineTo(tx, lineY + 8);
      ctx.strokeStyle = '#6B7280';
      ctx.lineWidth = 2;
      ctx.stroke();

      // Decimal below line
      ctx.fillStyle = '#9CA3AF';
      ctx.textBaseline = 'top';
      ctx.fillText(tickDecs[i], tx, lineY + 12);

      // Fraction above line
      ctx.textBaseline = 'bottom';
      ctx.fillText(tickFracs[i], tx, lineY - 12);
    }

    // Determine stage and target position of slider
    // 0 - 2s: 0.0
    // 2s - 4s: slide and stay at 0.25
    // 4s - 6s: slide and stay at 0.5
    // 6s - 8s: slide and stay at 0.75
    // 8s - 10s: slide and stay at 1.0
    // 10s - 12s: slide back to 0.0

    var currentVal = 0;
    var textDec = '0.0';
    var textFrac = '0/1';
    var stepExplain = 'Zero value';

    if (progress < 0.16) {
      currentVal = 0;
      textDec = '0.0';
      textFrac = '0/1';
      stepExplain = '0 tenths = 0 whole';
    } else if (progress >= 0.16 && progress < 0.33) {
      var slide = (progress - 0.16) / 0.08;
      var ease = Math.min(1, slide * slide * (3 - 2 * slide));
      currentVal = 0.25 * ease;
      textDec = '0.25';
      textFrac = '1/4';
      stepExplain = '25 hundredths = 1/4';
    } else if (progress >= 0.33 && progress < 0.50) {
      var slide = (progress - 0.33) / 0.08;
      var ease = Math.min(1, slide * slide * (3 - 2 * slide));
      currentVal = 0.25 + 0.25 * ease;
      textDec = '0.50';
      textFrac = '1/2';
      stepExplain = '5 tenths = 1/2';
    } else if (progress >= 0.50 && progress < 0.66) {
      var slide = (progress - 0.50) / 0.08;
      var ease = Math.min(1, slide * slide * (3 - 2 * slide));
      currentVal = 0.50 + 0.25 * ease;
      textDec = '0.75';
      textFrac = '3/4';
      stepExplain = '75 hundredths = 3/4';
    } else if (progress >= 0.66 && progress < 0.83) {
      var slide = (progress - 0.66) / 0.08;
      var ease = Math.min(1, slide * slide * (3 - 2 * slide));
      currentVal = 0.75 + 0.25 * ease;
      textDec = '1.0';
      textFrac = '1/1';
      stepExplain = '10 tenths = 1 whole';
    } else {
      var slide = (progress - 0.83) / 0.17;
      var ease = Math.min(1, slide * slide * (3 - 2 * slide));
      currentVal = 1.0 - 1.0 * ease;
      textDec = '0.0';
      textFrac = '0/1';
      stepExplain = 'Resetting scale...';
    }

    var sliderX = startX + currentVal * lineLen;

    // Draw glowing slider ball
    ctx.beginPath();
    ctx.arc(sliderX, lineY, 8, 0, Math.PI * 2);
    ctx.fillStyle = '#8B5CF6'; // Vibrant purple
    ctx.fill();
    ctx.strokeStyle = '#FFFFFF';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Text results at bottom
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    ctx.fillStyle = '#A78BFA';
    ctx.font = 'bold 18px -apple-system, sans-serif';
    ctx.fillText(textFrac + '   ↔   ' + textDec, W / 2, H - 42);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillText(stepExplain, W / 2, H - 22);
  }
};
